<!doctype html><html><head><style>@page{margin:35px}body{font-family:DejaVu Sans;color:#172033;font-size:11px}.box{border:1px solid #cbd5e1;padding:18px}.right{text-align:right}</style></head><body><div class="box"><table width="100%"><tr><td><strong>RETAILPOS.BIZ</strong><h1>Subscription Payment Receipt</h1></td><td class="right"><strong>{{ $payment->receipt_number }}</strong><br>{{ $payment->paid_at?->format('d M Y') }}</td></tr></table><hr><p><strong>Received from:</strong> {{ $invoice->billing_company ?: $invoice->billing_name }}</p><p><strong>Invoice:</strong> {{ $invoice->invoice_number }}</p><p><strong>Amount received:</strong> {{ $payment->currency }} {{ number_format((float)$payment->amount,2) }}</p><p><strong>Method:</strong> {{ str($payment->payment_method ?: $payment->provider)->replace('_',' ')->headline() }}</p><p><strong>Transaction reference:</strong> {{ $payment->transaction_reference ?: '-' }}</p><p><strong>Remaining invoice balance:</strong> {{ $invoice->currency }} {{ number_format((float)$invoice->balance_due,2) }}</p></div></body></html>
